const m=n=>{if(!n)return"—";const[e,a]=n.split(":"),t=parseInt(e),r=t>=12?"pm":"am";return`${t%12||12}:${a} ${r}`},u=(n=30,e="09:00",a="20:00")=>{const t=[],r=o=>{if(!o)return 0;const[p,i]=o.split(":").map(Number);return p*60+(i||0)};let s=r(e);const c=r(a);for(;s<c;){const o=Math.floor(s/60),p=s%60;t.push(`${String(o).padStart(2,"0")}:${String(p).padStart(2,"0")}`),s+=parseInt(n,10)||30}return t};export{m as f,u as g};
